236	                break;
237	
238	            default:
239	                warn('[WantedPosterManager] OnEvent: 未知的事件', event);
240	        }
241	    }
242	
243	    /**
244	     * @ch 依目前裝置方向套用對應的 Layout 設定
245	     * 由 start() 與 GAME_EVENT.DEVICE_ROTATION 事件觸發
246	     */
247	    private ApplyLayoutByOrientation(): void {
248	        if (!this.m_layout) {
249	            warn('[WantedPosterManager] ApplyLayoutByOrientation: m_layout 未設置');
250	            return;
251	        }
252	        const isLandscape = Common.GetGameView().IsLandscape;
253	        const cfg = isLandscape ? this.m_landscapeConfig : this.m_portraitConfig;
254	
255	        this.m_layout.type = cfg.type;
256	        this.m_layout.resizeMode = cfg.resizeMode;
257	        this.m_layout.paddingLeft = cfg.paddingLeft;
258	        this.m_layout.paddingRight = cfg.paddingRight;
259	        this.m_layout.paddingTop = cfg.paddingTop;
260	        this.m_layout.paddingBottom = cfg.paddingBottom;
261	        this.m_layout.spacingX = cfg.spacingX;
262	        this.m_layout.spacingY = cfg.spacingY;
263	        this.m_layout.alignHorizontal = cfg.alignHorizontal;
264	        this.m_layout.alignVertical = cfg.alignVertical;
265	        this.m_layout.updateLayout();
266	    }
267	
268	    /**
269	     * @ch 處理 PLAY_MARK 事件
270	     * BC-4：對該 BaseSymbol 的所有相符常駐 item 同時播 Mark，全部完成才 resolve
271	     *       （找到 N 個就播 N 個；N=0 才視為 EH-1，0<N 屬可接受降級不 warn）
272	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve（不阻斷上游流程）
273	     * EH-9：resolve callback 缺失 → error（caller bug）
274	     */
275	    private HandlePlayMark(baseSymbol: number, resolve: () => void) {
276	        if (typeof resolve !== 'function') {
277	            warn('[WantedPosterManager] PLAY_MARK: resolve callback 缺失');
278	            return;
279	        }
280	        const items = this.GetItemsByBaseSymbol(baseSymbol);
281	        if (items.length === 0) {
282	            warn('[WantedPosterManager] PLAY_MARK: 找不到對應 item, baseSymbol=', baseSymbol);
283	            resolve();
284	            return;
285	        }
286	        Promise.all(items.map(item => item.PlayMark())).then(() => resolve());
287	    }
288	
289	    /**
290	     * @ch 處理 PLAY_MARK_ACTIVE 事件
291	     * BC-6：對該 BaseSymbol 的所有相符 item 同時播 Mark_Active 並各自 active=false
292	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve
293	     * EH-9：resolve callback 缺失 → error
294	     */
295	    private HandlePlayMarkActive(baseSymbol: number, resolve: () => void) {
296	        if (typeof resolve !== 'function') {
297	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: resolve callback 缺失');
298	            return;
299	        }
300	        const items = this.GetItemsByBaseSymbol(baseSymbol);
301	        if (items.length === 0) {
302	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: 找不到對應 item, baseSymbol=', baseSymbol);
303	            resolve();
304	            return;
305	        }
306	        Promise.all(items.map(item =>
307	            item.PlayMarkActive().then(() => {
308	                item.node.active = false;
309	                // 收尾關閉 item → 同步清除綁定，避免與 m_currentBounty 失同步
310	                const idx = this.m_wantedPosterItems.indexOf(item);
311	                if (idx >= 0) this.m_currentBounty[idx] = null;
312	            })
313	        )).then(() => resolve());
314	    }
315	
316	    /**
317	     * @ch 處理 GAME_INTRO_COMPLETE 事件
318	     * 遊戲介紹完成後顯示 1 個懸賞令（M1、倍率 9999）
319	     * 複用 SetWantedPosterData 顯示路徑：isNewRound=true 走 BC-20 整批重建（SetData + active + PlayIn），
320	     * Multiple=9999 ≥ Multiplier_Max → item 內部走 m_x9999Node 顯示分支
321	     */
322	    private HandleGameIntroComplete() {
323	        // 介紹完成屬「全新展示」→ isNewRound=true，整批重建
324	        this.SetWantedPosterData([
325	            { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 9999, MultipleIndex: 0 },
326	        ], true);
327	    }
328	    //#endregion Event Management
329	
330	    //#region Methods
331	    /**
332	     * @ch 設置懸賞令資料（以 BaseSymbol multiset 比對前後狀態 — 決定 進場 / 退場 / 退場再進場 / 持續）
333	     *
334	     * 比對規則（內容式，計數 multiset；每個 BaseSymbol 綁定一個 item，持續者保留原綁定）：
335	     * - BC-20 isNewRound=true（新一局）→ 現有全部退場、新清單全部進場（整批重建）
336	     * - BC-21 同局・新增 BaseSymbol（計數增加）→ 進場（SetData + active + PlayIn）
337	     * - BC-22 同局・移除 BaseSymbol（計數減少）→ 退場（PlayOut → active=false）
338	     * - BC-23 同局・同 BaseSymbol・Multiple 變 → 原 item 退場再進場（PlayOut → SetData → PlayIn）
339	     * - BC-24 同局・同 BaseSymbol・Multiple 同・盤面(扣除被消除位置)已無此符號 → 原 item 退場再進場
340	     * - BC-25 同局・同 BaseSymbol・Multiple 同・盤面仍可見 → 持續，不播動畫
341	     * 位置重排一律交由 cc.Layout（本元件只處理 In/Out 動畫，不碰節點位置）。
342	     *
343	     * @param dataList 本輪懸賞令資料（Multiple>0 才顯示）
344	     * @param isNewRound 是否新一局（強制整批重建）；省略視為同局 cascade
345	     * @param visibleBaseSymbols 盤面(扣除被消除位置)目前可見的 BaseSymbol；僅 cascade 需傳，省略視為全可見
346	     */
347	    private SetWantedPosterData(dataList: IBountyData[], isNewRound: boolean = false, visibleBaseSymbols?: number[]) {
348	        if (!this.m_wantedPosterItems || this.m_wantedPosterItems.length === 0) {
349	            warn('[WantedPosterManager] SetWantedPosterData: 懸賞令物品未設置');
350	            return;
351	        }
352	        this.EnsureCurrentBountySize();
353	
354	        const count = this.m_wantedPosterItems.length;
355	        // 本輪要顯示的 bounty（Multiple>0），超量截斷至 item 數量上限
356	        const newBounties = dataList.filter(d => d && d.Multiple > 0);
357	        if (newBounties.length > count) {
358	            warn('[WantedPosterManager] SetWantedPosterData: 資料數量超過物品數量',
359	                newBounties.length, '>', count);
360	            newBounties.length = count;
361	        }
362	
363	        if (isNewRound) {
364	            this.RebuildAll(newBounties);
365	        } else {
366	            this.ReconcileCascade(newBounties, visibleBaseSymbols);
367	        }
368	    }
369	
370	    /**
371	     * @ch BC-20 整批重建（新一局）：現有全部 Out 並關閉，全部 Out 完成後新清單依序設資料、active、PlayIn。
372	     *     先 Out 再一起 In，避免新舊同時在場造成 Layout 重排跳動。
373	     *     綁定同步記錄為目標狀態（視覺在 Out 完成後才 In）。
374	     */
375	    private RebuildAll(newBounties: IBountyData[]) {
376	        const count = this.m_wantedPosterItems.length;
377	
378	        const outPromises: Promise<void>[] = [];
379	        for (let i = 0; i < count; i++) {
380	            const item = this.m_wantedPosterItems[i];
381	            if (item && item.node.active) {
382	                outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
383	            }
384	            // 同步記錄目標綁定（前 newBounties.length 個為新資料，其餘清空）
385	            this.m_currentBounty[i] = i < newBounties.length ? newBounties[i] : null;
386	        }
387	
388	        const enterAll = () => {
389	            for (let i = 0; i < newBounties.length; i++) {
390	                const item = this.m_wantedPosterItems[i];
391	                if (!item) continue;
392	                item.SetWantedPosterData(newBounties[i]);
393	                item.node.active = true;
394	                item.PlayIn();
395	            }
396	        };
397	
398	        if (outPromises.length > 0) Promise.all(outPromises).then(enterAll);
399	        else enterAll();
400	    }
401	
402	    /**
403	     * @ch 同局 cascade 對帳：以 BaseSymbol multiset 比對目前綁定 ↔ 新清單，保留持續者的 item 綁定。
404	     *     - 同 BaseSymbol・Multiple 同・盤面仍可見 → 持續（不動）         [BC-25]
405	     *     - 同 BaseSymbol・Multiple 變 或 盤面已無此符號 → 原 item 退場再進場 [BC-23/BC-24]
406	     *     - 多出的新 BaseSymbol → 進場（優先用原本就空的 item；不足才等退場者騰出版位）[BC-21]
407	     *     - 少掉的舊 BaseSymbol → 退場                                  [BC-22]
408	     * @param visibleBaseSymbols 盤面(扣除被消除位置)可見的 BaseSymbol；省略視為全可見
409	     */
410	    private ReconcileCascade(newBounties: IBountyData[], visibleBaseSymbols?: number[]) {
411	        const count = this.m_wantedPosterItems.length;
412	        const visible = visibleBaseSymbols ? new Set(visibleBaseSymbols) : null;
413	
414	        // 新清單依 BaseSymbol 分組成可消耗的 pool（multiset）
415	        const pool = new Map<number, IBountyData[]>();
416	        for (const b of newBounties) {
417	            const list = pool.get(b.BaseSymbol);
418	            if (list) list.push(b); else pool.set(b.BaseSymbol, [b]);
419	        }
420	
421	        const preFreeSlots: number[] = [];      // 更新前就空著的 item，供進場立即使用
422	        const vacatingSlots: number[] = [];     // 本輪退場騰出的 item，Out 完才可用
423	        const outPromises: Promise<void>[] = [];
424	        const deferredEnter: IBountyData[] = [];
425	
426	        // Pass A：逐一決定目前已綁定 item 的命運
427	        for (let i = 0; i < count; i++) {
428	            const cur = this.m_currentBounty[i];
429	            const item = this.m_wantedPosterItems[i];
430	            if (cur === null) {
431	                if (item) preFreeSlots.push(i);
432	                continue;
433	            }
434	            const bs = cur.BaseSymbol;
435	            const list = pool.get(bs);
436	            if (list && list.length > 0) {
437	                const onBoard = visible ? visible.has(bs) : true;
438	                // 優先配對「相同 Multiple」以持續（不播動畫）；盤面不可見則一律退場再進場
439	                const sameIdx = onBoard ? list.findIndex(b => b.Multiple === cur.Multiple) : -1;
440	                if (sameIdx >= 0) {
441	                    list.splice(sameIdx, 1);                 // BC-25 持續：消耗一筆，item 不動
442	                } else {
443	                    const nb = list.shift()!;                // BC-23/BC-24 退場再進場
444	                    if (item) item.PlayOut().then(() => { item.SetWantedPosterData(nb); item.PlayIn(); });
445	                    this.m_currentBounty[i] = nb;
446	                }
447	                if (list.length === 0) pool.delete(bs);
448	            } else {
449	                // BC-22 新清單已無此 BaseSymbol → 退場
450	                if (item) outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
451	                this.m_currentBounty[i] = null;
452	                vacatingSlots.push(i);
453	            }
454	        }
455	
456	        // Pass B：pool 剩餘 = 需進場的新 BaseSymbol [BC-21]
457	        const remaining: IBountyData[] = [];
458	        for (const list of pool.values()) remaining.push(...list);
459	        for (const nb of remaining) {
460	            if (preFreeSlots.length > 0) {
461	                this.EnterAt(preFreeSlots.shift()!, nb);     // 有現成空位 → 立即進場
462	            } else {
463	                deferredEnter.push(nb);                      // 無現成空位 → 等退場者騰出
464	            }
465	        }
466	
467	        // 不足的進場等所有退場完成後，使用騰出的 item 版位
468	        if (deferredEnter.length > 0) {
469	            Promise.all(outPromises).then(() => {
470	                for (const nb of deferredEnter) {
471	                    const idx = vacatingSlots.shift();
472	                    if (idx === undefined) break;            // 理論上不會（已截斷至 count）
473	                    this.EnterAt(idx, nb);
474	                }
475	            });
476	        }
477	    }
478	
479	    /**@ch 在指定 item 版位進場：設資料、active、PlayIn 並記錄綁定*/
480	    private EnterAt(index: number, data: IBountyData) {
481	        const item = this.m_wantedPosterItems[index];
482	        if (!item) return;
483	        item.SetWantedPosterData(data);
484	        item.node.active = true;
485	        item.PlayIn();
486	        this.m_currentBounty[index] = data;
487	    }
488	
489	    /**@ch 確保綁定追蹤陣列長度與 item 數一致（初次/變動時補 null、保留既有）*/
490	    private EnsureCurrentBountySize() {
491	        const count = this.m_wantedPosterItems.length;
492	        if (this.m_currentBounty.length === count) return;
493	        const next: (IBountyData | null)[] = new Array(count).fill(null);
494	        const keep = Math.min(this.m_currentBounty.length, count);
495	        for (let i = 0; i < keep; i++) next[i] = this.m_currentBounty[i];
496	        this.m_currentBounty = next;
497	    }
498	
499	    /**
500	     * @ch 依 BaseSymbol 取得**所有**相符的 active 常駐 item（內部用，PLAY_MARK / PLAY_MARK_ACTIVE 路徑）
501	     * 同一盤面允許多筆同 BaseSymbol bounty（各自設到不同 index 的 item），故回陣列而非單一
502	     */
503	    private GetItemsByBaseSymbol(baseSymbol: number): WantedPosterItem[] {
504	        if (baseSymbol === null || baseSymbol === undefined) return [];
505	        const result: WantedPosterItem[] = [];
506	        for (const item of this.m_wantedPosterItems) {
507	            if (item && item.node.active && item.GetBaseSymbol() === baseSymbol) {
508	                result.push(item);
509	            }
510	        }
511	        return result;
512	    }
513	    /**
514	     * @ch 設置懸賞令 UI 顯示狀態
515	     * @param isShow 是否顯示
516	     */
517	    private SetWantedPosterUIShow(isShow: boolean) {
518	        if (!this.m_rootNode) {
519	            warn('[WantedPosterManager] SetWantedPosterUIShow: 根節點未設置');
520	            return;
521	        }
522	        this.m_rootNode.active = isShow;
523	    }
524	    //#endregion Methods
525	
526	    //#region 測試功能
527	    /**
528	     * @ch 測試按鍵處理
529	     * - 數字鍵 1：顯示 1 個懸賞令
530	     * - 數字鍵 2：顯示 2 個懸賞令
531	     * - 數字鍵 3：顯示 UI
532	     * - 數字鍵 4：隱藏 UI
533	     */
534	    private CheckTestKeyCode(event: EventKeyboard): void {
535	        if (!DEBUG) return;
536	        switch (event.keyCode) {
537	            case KeyCode.DIGIT_1:
538	                log('[WantedPosterManager] 測試：顯示 1 個懸賞令');
539	                this.SetWantedPosterData([
540	                    { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 2, MultipleIndex: 0 },
541	                ], true);
542	                break;
543	
544	            case KeyCode.DIGIT_2:
545	                log('[WantedPosterManager] 測試：顯示 2 個懸賞令');
546	                this.SetWantedPosterData([
547	                    { BaseSymbol: Symbol.M4, BountySymbol: 0, Multiple: 256, MultipleIndex: 0 },
548	                    { BaseSymbol: Symbol.M8, BountySymbol: 0, Multiple: 9999, MultipleIndex: 1 },
549	                ], true);
550	                break;
551	
552	            case KeyCode.DIGIT_3:
553	                log('[WantedPosterManager] 測試：顯示 UI');
554	                this.SetWantedPosterUIShow(true);
555	                break;
556	
557	            case KeyCode.DIGIT_4:
558	                log('[WantedPosterManager] 測試：隱藏 UI');
559	                this.SetWantedPosterUIShow(false);
560	                break;
561	        }
562	    }
563	    //#endregion 測試功能
564	}
